    // If we use $d' \in D$, we can reduce $x$ to $d'$ if $d' | x$.

    // Let $d_i = \min \{d \in \text{unique}(nums) \mid d \text{ divides } nums_i\}$.
    // If we can show that $nums_i$ can always be reduced to $d_i$, then the minimum sum is $\sum d_i$.

    // Proof sketch: Let $d_i$ be the smallest divisor of $nums_i$ that is present in $nums$.
    // Let $d_i$ be achieved by an element $nums_b$. Since $d_i | nums_i$, we can perform the operation
    // $nums_i \to nums_b$ if $nums_b$ is present. Since $d_i$ is present in the original array, it is present
    // at $t=0$. Thus, $nums_i$ can become $d_i$ in one step.
    // Since we want the minimum sum, we choose this smallest possible replacement for each element independently.
    // The operations on one element do not prevent another element from being reduced to its own minimal divisor.

    const uniqueNums = Array.from(new Set(nums));
    let minSum = 0;

    for (const num of nums) {
        let smallestDivisor = num; // Initialize to itself (worst case)

        for (const d of uniqueNums) {
            if (d === 0) continue; // Should not happen based on constraints
            if (num % d === 0) {
                // d is a divisor of num, and d is present in the original array.
                // We want the smallest such d.
                if (d < smallestDivisor) {
                    smallestDivisor = d;
                }
            }
        }
        minSum += smallestDivisor;
    }

    return minSum;
}

