fun solve(nums: Array<Long>): Long {
    // The core insight is that for any element nums[i], the smallest value it can possibly be replaced by
    // is the smallest element 'd' present in the original array such that 'd' divides nums[i].
    // This is because if 'd' is present, and nums[i] % d == 0, we can replace nums[i] with d in one operation.
    // Since we want the minimum total sum, we greedily choose the smallest possible divisor from the set of unique initial values for each element.

    val uniqueNums = nums.toSet().toLongArray()
    var minSum: Long = 0

    for (num in nums) {
        var smallestDivisor = num // Initialize to itself (worst case: no smaller divisor found)

        for (d in uniqueNums) {
            if (d == 0L) continue // Constraint ensures nums[i] >= 1

            if (num % d == 0L) {
                // d is a divisor of num, and d is present in the original array.
                if (d < smallestDivisor) {
                    smallestDivisor = d
                }
            }
        }
        minSum += smallestDivisor
    }

    return minSum
}
